// ============================================
// FORMAT EMAIL TRANSCRIPT (Outlook/Gmail Compatible)
// ============================================

// Get contact from workflow input
const workflowInput = $('When Executed by Another Workflow').first().json;

const contact = {
  full_name: workflowInput.user_name || 'Guest',
  email: workflowInput.user_email,
  phone: workflowInput.user_phone || 'N/A',
  session_id: workflowInput.sessionId,
  client_id: workflowInput.client_id,
  created_at: new Date().toISOString()
};

const chatMessages = $input.all();

// Helper: escape HTML and convert newlines to <br>
function escapeHtml(text) {
  if (!text) return '';
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/\n/g, '<br>');
}

// Format messages as HTML table rows
let transcriptRows = '';
if (chatMessages && chatMessages.length > 0) {
  chatMessages.forEach((item) => {
    const data = item.json;
    const role = data.role || 'unknown';
    const messageText = data.message_text || '';

    // Filter out system messages
    if (messageText && 
        messageText.indexOf('STORE_USER_DATA') === -1 && 
        messageText.indexOf('CHAT_END_CONFIRMED') === -1) {

      const isCustomer = role === 'human';
      const bgColor = isCustomer ? '#e3f2fd' : '#f5f5f5';
      const borderColor = isCustomer ? '#2196f3' : '#9e9e9e';
      const roleLabel = isCustomer ? '👤 Customer' : '🤖 Agent';

      transcriptRows += `
        <tr>
          <td style="padding: 12px 16px; background-color: ${bgColor}; border-left: 4px solid ${borderColor}; margin-bottom: 8px;">
            <div style="font-weight: bold; color: #333; margin-bottom: 6px; font-size: 13px;">${roleLabel}</div>
            <div style="color: #444; font-size: 14px; line-height: 1.5;">${escapeHtml(messageText)}</div>
          </td>
        </tr>
        <tr><td style="height: 8px;"></td></tr>
      `;
    }
  });
}

if (!transcriptRows) {
  transcriptRows = '<tr><td style="padding: 20px; color: #666; font-style: italic;">(No chat history found)</td></tr>';
}

const dateStr = new Date().toLocaleDateString('en-GB', { day: '2-digit', month: 'long', year: 'numeric' });
const timeStr = new Date().toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' });

// Build Outlook/Gmail compatible HTML using tables
const emailHTML = `
<!DOCTYPE html PUBLIC "-//W3C//DTD XHTML 1.0 Transitional//EN" "http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd">
<html xmlns="http://www.w3.org/1999/xhtml">
<head>
  <meta http-equiv="Content-Type" content="text/html; charset=UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>Chat Transcript</title>
</head>
<body style="margin: 0; padding: 0; font-family: Arial, Helvetica, sans-serif; background-color: #f4f4f4;">
  <table border="0" cellpadding="0" cellspacing="0" width="100%" style="background-color: #f4f4f4;">
    <tr>
      <td align="center" style="padding: 20px 10px;">
        <table border="0" cellpadding="0" cellspacing="0" width="600" style="max-width: 600px; width: 100%;">

          <!-- Header -->
          <tr>
            <td align="center" style="background-color: #667eea; padding: 30px 20px; border-radius: 8px 8px 0 0;">
              <h1 style="margin: 0; color: #ffffff; font-size: 24px; font-weight: bold;">📋 Chat Transcript</h1>
              <p style="margin: 10px 0 0 0; color: #e8eaff; font-size: 14px;">Your conversation with ${contact.client_id || 'Realtysoft'}</p>
            </td>
          </tr>

          <!-- Content -->
          <tr>
            <td style="background-color: #ffffff; padding: 30px 25px;">

              <!-- Contact Info Box -->
              <table border="0" cellpadding="0" cellspacing="0" width="100%" style="background-color: #f9f9f9; border-left: 4px solid #667eea; margin-bottom: 25px;">
                <tr>
                  <td style="padding: 20px;">
                    <h3 style="margin: 0 0 15px 0; color: #667eea; font-size: 16px;">👤 Contact Information</h3>
                    <p style="margin: 6px 0; color: #333; font-size: 14px;"><strong>Name:</strong> ${contact.full_name}</p>
                    <p style="margin: 6px 0; color: #333; font-size: 14px;"><strong>Email:</strong> ${contact.email || 'N/A'}</p>
                    <p style="margin: 6px 0; color: #333; font-size: 14px;"><strong>Phone:</strong> ${contact.phone}</p>
                    <p style="margin: 6px 0; color: #333; font-size: 14px;"><strong>Date:</strong> ${dateStr} at ${timeStr}</p>
                  </td>
                </tr>
              </table>

              <!-- Transcript Section -->
              <h3 style="margin: 0 0 15px 0; color: #333; font-size: 16px;">💬 Conversation Transcript</h3>
              <table border="0" cellpadding="0" cellspacing="0" width="100%" style="background-color: #fafafa; border: 1px solid #e0e0e0; border-radius: 4px;">
                ${transcriptRows}
              </table>

            </td>
          </tr>

          <!-- Footer -->
          <tr>
            <td align="center" style="background-color: #f9f9f9; padding: 20px; border-top: 1px solid #e0e0e0; border-radius: 0 0 8px 8px;">
              <p style="margin: 0; color: #666; font-size: 12px;">This transcript was automatically generated by ${contact.client_id || 'Realtysoft'}.</p>
              <p style="margin: 5px 0 0 0; color: #666; font-size: 12px;">If you have any questions, please contact us directly.</p>
            </td>
          </tr>

        </table>
      </td>
    </tr>
  </table>
</body>
</html>
`;

// Plain text version
let transcriptText = '';
if (chatMessages && chatMessages.length > 0) {
  chatMessages.forEach((item) => {
    const data = item.json;
    const role = data.role || 'unknown';
    const messageText = data.message_text || '';
    if (messageText && messageText.indexOf('STORE_USER_DATA') === -1 && messageText.indexOf('CHAT_END_CONFIRMED') === -1) {
      const roleLabel = role === 'human' ? 'Customer' : 'Agent';
      transcriptText += `\n${roleLabel}:\n${messageText}\n`;
    }
  });
}

const emailText = `CHAT TRANSCRIPT\n===============\n\nContact Information:\n--------------------\nName: ${contact.full_name}\nEmail: ${contact.email || 'N/A'}\nPhone: ${contact.phone}\nDate: ${dateStr} at ${timeStr}\n\nConversation Transcript:\n========================\n${transcriptText || '(No chat history found)'}\n\n---\nThis transcript was automatically generated by ${contact.client_id || 'Realtysoft'}.`;

return {
  to: contact.email,
  to_name: contact.full_name,
  subject: `Chat Transcript - ${contact.client_id || 'Realtysoft'} - ${new Date().toLocaleDateString('en-GB')}`,
  html: emailHTML,
  text: emailText,
  session_id: contact.session_id,
  client_id: contact.client_id,
  owner_email: workflowInput.owner_email
};

// Log the error for debugging
const error = $input.first().json;

console.log('=== EMAIL TRANSCRIPT ERROR ===');
console.log('Error:', error);

// Get the original workflow input data
const workflowInput = $('When Executed by Another Workflow').first().json;

// Return session_id for marking chat as ended
return {
  json: {
    session_id: workflowInput.sessionId,
    error_occurred: true,
    error_message: error.message || 'Unknown error during email sending',
    error_node: error.node?.name || 'Unknown node'
  }
};
